// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import { IERC20 } from "lib/openzeppelin-contracts/contracts/token/ERC20/IERC20.sol";

interface IClaudelanceCore {
    enum BountyStatus { Open, Resolved, Cancelled }

    struct Bounty {
        address poster;
        uint96 amount;
        address winner;
        uint96 stakeRequired;
        address token;
        uint64 deadline;
        uint8 maxSlots;
        uint8 claimedSlots;
        uint8 bountyType;
        bool ciRequired;
        address targetWorker;
        BountyStatus status;
        string targetRepoUrl;
        string instructionUrl;
        bytes32 requirementsHash;
    }

    struct Submission {
        bytes32 commitHash;
        uint64 submittedAt;
        bool ciPassed;
        bool stakeRefunded;
        string prUrl;
        string metadata;
    }

    struct PendingAddress {
        address proposed;
        uint64 effectiveAt;
    }
}
